input.command:
PW=$(kubectl get secret -n mongodb admin-user-password -o jsonpath='{.data.password}' | base64 -d)

echo "=== Replica set member states ==="
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet \
  "mongodb://admin-user:$PW@localhost:27017/admin?directConnection=true" \
  --eval "rs.status().members.forEach(m => print(m.name, m.stateStr))"

echo ""
echo "=== Config verification per member ==="
for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "--- $pod ---"
  kubectl exec -n mongodb $pod -- mongosh --quiet \
    "mongodb://admin-user:$PW@localhost:27017/admin?directConnection=true" \
    --eval "
      var lv = db.adminCommand({getParameter:1, logLevel:1}).logLevel;
      var ps = db.getProfilingStatus();
      var opts = db.adminCommand({getCmdLineOpts:1}).parsed;
      var jc = (opts.storage && opts.storage.wiredTiger && opts.storage.wiredTiger.engineConfig)
               ? opts.storage.wiredTiger.engineConfig.journalCompressor : 'not-in-parsed';
      print('logLevel=' + lv + ' slowms=' + ps.slowms + ' journalCompressor=' + jc);
    "
done
